const msg = $input.item.json.message || {};
const texto = (msg.text || '').trim();
const chatId = msg.chat ? msg.chat.id : null;
const fromId = msg.from ? msg.from.id : null;
const DIRETOR_CHAT_ID = parseInt($env.TELEGRAM_CHAT_ID_DIRETOR || '0');

// Verificar se e o Diretor
const isDiretor = (chatId === DIRETOR_CHAT_ID || fromId === DIRETOR_CHAT_ID);

// Parsear comando
// Formatos aceitos: /aprovar A , /rejeitar B , /veredito D1:A D2:B
const cmdMatch = texto.match(/^\/(aprovar|rejeitar|veredito)\s+(.+)/i);
if (!cmdMatch) {
  return [{ json: { valido: false, motivo: 'Formato invalido -- use /aprovar A ou /rejeitar B', chatId: chatId } }];
}

const cmd = cmdMatch[1].toLowerCase();
const arg = cmdMatch[2].trim().toUpperCase();

// Parsear itens: "A" ou "D1:A D2:B D3:C"
let itens = [];
if (cmd === 'veredito') {
  const matches = arg.match(/D\d+:[ABC]/gi);
  if (matches) itens = matches.map(m => ({ id: m.split(':')[0], veredito: m.split(':')[1] }));
} else {
  // /aprovar A ou /rejeitar B
  const v = cmd === 'aprovar' ? 'A' : 'B';
  itens = [{ id: arg, veredito: v }];
}

const agora = new Date();
const data = agora.toLocaleDateString('pt-BR', { timeZone: 'America/Sao_Paulo' });
const hora = agora.toLocaleTimeString('pt-BR', { timeZone: 'America/Sao_Paulo', hour: '2-digit', minute: '2-digit' });

return [{ json: { valido: true, isDiretor: isDiretor, cmd: cmd, itens: itens, texto: texto, chatId: chatId, data: data, hora: hora } }];

const item = $('Parsear Comando').item.json;
const linhas = item.itens.map(i => '[' + i.veredito + '] ' + i.id);
const resumo = '[VEREDITO] ' + item.data + ' ' + item.hora + ' | ' + linhas.join(' | ');
const body = { children: [{ object: 'block', type: 'paragraph', paragraph: { rich_text: [{ type: 'text', text: { content: resumo } }] } }] };
const confirmacao = 'Veredito registrado:\n' + linhas.map(l => '  ' + l).join('\n') + '\n\n' + item.data + ' ' + item.hora;
return [{ json: { notionBody: JSON.stringify(body), confirmacao: confirmacao, chatId: item.chatId } }];
